import React, { useState, useMemo } from 'react';
import {
    ChevronDown, ChevronUp, PlusCircle, Edit3, MinusCircle, Equal,
    FileText, Calendar, Layers, ArrowRight,
} from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { renderSampleFieldVal, getSystemStatus } from '@/utils/field-renderers';
import type { DiffStatus, CTDiffItem, EntryDiffItem, LocaleDiffItem } from '@/types/smart-migrate';

const DIFF_BADGE: Record<DiffStatus, { label: string; className: string; icon: React.ReactNode }> = {
    NEW: {
        label: 'NEW',
        className: 'bg-emerald-500/10 text-emerald-400 border-emerald-500/30',
        icon: <PlusCircle className="h-3 w-3" />,
    },
    MODIFIED: {
        label: 'MODIFIED',
        className: 'bg-amber-500/10 text-amber-400 border-amber-500/30',
        icon: <Edit3 className="h-3 w-3" />,
    },
    DELETED: {
        label: 'DELETED',
        className: 'bg-rose-500/10 text-rose-400 border-rose-500/30',
        icon: <MinusCircle className="h-3 w-3" />,
    },
    EQUAL: {
        label: 'EQUAL',
        className: 'bg-muted/30 text-muted-foreground border-white/10',
        icon: <Equal className="h-3 w-3" />,
    },
};

export function DiffBadge({ status }: { status: DiffStatus }) {
    const cfg = DIFF_BADGE[status];
    return (
        <Badge
            variant="outline"
            className={`h-5 px-2 text-base font-bold uppercase tracking-wider flex items-center gap-1 ${cfg.className}`}
        >
            {cfg.icon}
            {cfg.label}
        </Badge>
    );
}

export function MigrateEntryRow({
    entry,
    checked,
    onToggle,
    resolvedAssets,
    resolvedEntries,
}: {
    entry: EntryDiffItem;
    checked: boolean;
    onToggle: (id: string, checked: boolean) => void;
    resolvedAssets?: CTDiffItem['resolvedAssets'];
    resolvedEntries?: CTDiffItem['resolvedEntries'];
}) {
    const [expanded, setExpanded] = useState(false);
    const isDeleted = entry.diffStatus === 'DELETED';
    const isModified = entry.diffStatus === 'MODIFIED';

    const fields = entry.fields as Record<string, Record<string, unknown>> | undefined;
    const targetFields = entry.targetFields as Record<string, Record<string, unknown>> | undefined;

    const updatedStr = entry.sys?.updatedAt
        ? new Intl.DateTimeFormat('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: 'numeric' }).format(new Date(entry.sys.updatedAt))
        : null;

    return (
        <div className={`flex flex-col rounded-lg border transition-colors overflow-hidden ${isDeleted
            ? 'border-rose-500/15 bg-rose-500/3 opacity-60'
            : checked
                ? 'border-primary/20 bg-card/40'
                : 'border-white/5 bg-card/10 hover:bg-card/30'
            }`}>
            <div className="flex items-center gap-3 p-3 cursor-pointer select-none" onClick={() => setExpanded(v => !v)}>
                <Checkbox
                    id={`entry-${entry.id}`}
                    checked={checked}
                    onCheckedChange={(v) => { v !== 'indeterminate' && onToggle(entry.id, !!v); }}
                    className="shrink-0"
                    disabled={isDeleted}
                    onClick={(e) => e.stopPropagation()}
                />
                <div className="flex items-center gap-3 w-[40%] min-w-0 pr-4">
                    <div className={`h-2 w-2 rounded-full shrink-0 ${entry.diffStatus === 'NEW' ? 'bg-emerald-400' :
                        entry.diffStatus === 'MODIFIED' ? 'bg-amber-400' :
                            entry.diffStatus === 'DELETED' ? 'bg-rose-400' : 'bg-muted-foreground'
                        }`} />
                    <span className={`font-bold text-foreground text-base truncate ${isDeleted ? 'line-through text-muted-foreground' : ''}`}>
                        {entry.title}
                    </span>
                </div>
                <div className="flex-1 min-w-0 flex items-center text-base text-muted-foreground gap-4">
                    <DiffBadge status={entry.diffStatus} />
                    {isModified && entry.changedFieldKeys && (
                        <span className="text-base text-amber-400/80">
                            {entry.changedFieldKeys.length} field{entry.changedFieldKeys.length !== 1 ? 's' : ''} changed
                        </span>
                    )}
                    {updatedStr && (
                        <span className="truncate flex items-center gap-1">
                            <Calendar className="h-3.5 w-3.5" />
                            {updatedStr}
                        </span>
                    )}
                    <div className="ml-auto flex items-center gap-2">
                        {getSystemStatus(entry.sys)}
                        {expanded ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
                    </div>
                </div>
            </div>

            {expanded && fields && (
                <div className="border-t border-white/5 bg-black/20 p-5">
                    <div className="flex flex-col gap-6">
                        {Object.entries(fields).map(([fieldKey, fieldVal]) => {
                            const isChanged = isModified && entry.changedFieldKeys?.includes(fieldKey);
                            return (
                                <div key={fieldKey} className={`flex flex-col gap-2 p-4 rounded-lg ${isChanged ? 'bg-amber-500/5 border border-amber-500/10' : 'bg-white/2 border border-white/5'}`}>
                                    <div className="flex items-center gap-2">
                                        <span className="text-base font-black uppercase tracking-widest text-muted-foreground/60">{fieldKey}</span>
                                        {isChanged && (
                                            <Badge variant="outline" className="h-5 px-2 text-base border-amber-500/30 text-amber-400 whitespace-nowrap">
                                                Changed
                                            </Badge>
                                        )}
                                    </div>
                                    <div className="text-base">
                                        {renderSampleFieldVal(fieldVal, resolvedAssets, resolvedEntries)}
                                    </div>
                                    {isChanged && targetFields?.[fieldKey] && (
                                        <div className="text-base border-t border-amber-500/10 pt-2 mt-1 opacity-60">
                                            <span className="text-base font-bold text-rose-400/80 mb-1 block">Target (current):</span>
                                            {renderSampleFieldVal(targetFields[fieldKey], resolvedAssets, resolvedEntries)}
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}
        </div>
    );
}

import type { DiffEntriesResult } from '@/hooks/useSmartMigrate';

export function MigrateCTRow({
    ct,
    checked,
    isAutoDep,
    onToggle,
    entriesData,
    isLoadingEntries,
    onLoadEntries,
    selectedEntryIds,
    onToggleEntry,
    onSelectAllEntries,
    onClearEntries,
    entrySearch,
    hideUnchanged,
}: {
    ct: CTDiffItem;
    checked: boolean;
    isAutoDep: boolean;
    onToggle: (id: string, checked: boolean) => void;
    entriesData?: DiffEntriesResult;
    isLoadingEntries: boolean;
    onLoadEntries: (ctId: string) => void;
    selectedEntryIds: Set<string>;
    onToggleEntry: (id: string, checked: boolean) => void;
    onSelectAllEntries: (ctId: string) => void;
    onClearEntries: (ctId: string) => void;
    entrySearch: string;
    hideUnchanged: boolean;
}) {
    const [expanded, setExpanded] = useState(false);

    // We fetch entries when expanded
    React.useEffect(() => {
        if (expanded && !entriesData && !isLoadingEntries && ct.diffStatus !== 'DELETED') {
            onLoadEntries(ct.id);
        }
    }, [expanded, entriesData, isLoadingEntries, ct.id, ct.diffStatus, onLoadEntries]);

    const isDeleted = ct.diffStatus === 'DELETED';
    const hasChanges = ct.diffStatus !== 'EQUAL';

    const rawEntries = entriesData?.entries ?? [];
    const filteredEntries = useMemo(() => {
        let list = rawEntries;
        if (hideUnchanged) {
            list = list.filter(e => e.diffStatus !== 'EQUAL');
        }
        if (entrySearch) {
            const q = entrySearch.toLowerCase();
            list = list.filter(e => e.title.toLowerCase().includes(q) || e.id.toLowerCase().includes(q));
        }
        return list;
    }, [rawEntries, entrySearch, hideUnchanged]);

    const selectedCount = rawEntries.filter(e => selectedEntryIds.has(e.id)).length;
    const newCount = rawEntries.filter(e => e.diffStatus === 'NEW').length;
    const modCount = rawEntries.filter(e => e.diffStatus === 'MODIFIED').length;
    // The diff logic previously replaced this block.

    return (
        <div className={`rounded-xl border transition-all ${isDeleted
            ? 'border-rose-500/20 bg-rose-500/5 opacity-70'
            : checked
                ? 'border-primary/40 bg-primary/10 shadow-sm shadow-primary/5'
                : hasChanges
                    ? 'border-white/10 bg-black/20 hover:bg-white/5'
                    : 'border-white/5 bg-black/20'
            }`}>
            <div className="flex items-center gap-4 px-4 py-4">
                <Checkbox
                    id={`ct-${ct.id}`}
                    checked={checked}
                    onCheckedChange={(v) => onToggle(ct.id, !!v)}
                    className="shrink-0 h-5 w-5"
                    disabled={isAutoDep || isDeleted}
                />
                <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 flex-wrap">
                        <Label
                            htmlFor={`ct-${ct.id}`}
                            className={`text-lg font-semibold cursor-pointer ${isDeleted ? 'line-through text-muted-foreground' : ''}`}
                        >
                            {ct.name}
                        </Label>
                        <span className="text-base font-mono text-muted-foreground/50">{ct.id}</span>
                        <DiffBadge status={ct.diffStatus} />
                        {isAutoDep && (
                            <Badge variant="secondary" className="h-5 px-2 text-base bg-amber-500/10 text-amber-400 border-amber-500/20">
                                auto-dep
                            </Badge>
                        )}
                    </div>
                    <div className="flex items-center gap-3 mt-1 text-base text-muted-foreground">
                        <span className="flex items-center gap-1">
                            <FileText className="h-3.5 w-3.5" />
                            {ct.totalSourceEntries} source ┬╖ {ct.totalTargetEntries} target
                        </span>
                        {newCount > 0 && <span className="text-emerald-400 font-semibold">+{newCount} new</span>}
                        {modCount > 0 && <span className="text-amber-400 font-semibold">~{modCount} modified</span>}
                        {ct.deletedEntryCount > 0 && <span className="text-rose-400/70">-{ct.deletedEntryCount} deleted</span>}
                        {selectedCount > 0 && <span className="text-primary font-semibold">{selectedCount} selected</span>}
                    </div>
                    {ct.changedFields && ct.changedFields.length > 0 && (
                        <p className="text-base text-amber-500/80 mt-1 font-mono">Schema: {ct.changedFields.join(', ')}</p>
                    )}
                </div>
                {!isDeleted && (
                    <button
                        onClick={() => setExpanded(v => !v)}
                        className="text-muted-foreground hover:text-foreground transition-colors shrink-0 flex items-center gap-1"
                    >
                        <Layers className="h-4 w-4" />
                        <span className="text-base font-bold">{expanded ? 'Hide entries' : 'Show entries'}</span>
                        {expanded ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
                    </button>
                )}
            </div>

            {expanded && (
                <div className="border-t border-white/5">
                    {isLoadingEntries && !entriesData ? (
                        <div className="flex items-center justify-center p-8 text-muted-foreground text-sm gap-2">
                            <div className="w-4 h-4 rounded-full border-2 border-primary border-t-transparent animate-spin" />
                            Loading entries...
                        </div>
                    ) : entriesData ? (
                        <>
                            <div className="flex items-center gap-2 px-4 py-2 bg-white/[0.02] text-base">
                                <button onClick={() => onSelectAllEntries(ct.id)} className="text-primary font-bold hover:underline">Select all</button>
                                <span className="text-muted-foreground/30">┬╖</span>
                                <button onClick={() => onClearEntries(ct.id)} className="text-muted-foreground font-bold hover:underline">None</button>
                                <span className="ml-auto text-muted-foreground/60">
                                    {filteredEntries.length} entr{filteredEntries.length !== 1 ? 'ies' : 'y'}
                                </span>
                            </div>
                            <div className="px-4 pb-4 pt-2 space-y-2 max-h-[500px] overflow-y-auto">
                                {filteredEntries.map(entry => (
                                    <MigrateEntryRow
                                        key={entry.id}
                                        entry={entry}
                                        checked={selectedEntryIds.has(entry.id)}
                                        onToggle={onToggleEntry}
                                        resolvedAssets={entriesData.resolvedAssets}
                                        resolvedEntries={entriesData.resolvedEntries}
                                    />
                                ))}
                                {filteredEntries.length === 0 && (
                                    <div className="text-center text-base text-muted-foreground/40 py-4">No entries to show</div>
                                )}
                            </div>
                        </>
                    ) : (
                        <div className="p-4 text-center text-rose-400 text-sm">Failed to load entries</div>
                    )}
                </div>
            )}
        </div>
    );
}

export function MigrateLocaleRow({
    locale,
    checked,
    remappedTo,
    onToggle,
}: {
    locale: LocaleDiffItem;
    checked: boolean;
    remappedTo?: string;
    onToggle: (code: string, checked: boolean) => void;
}) {
    const isDeleted = locale.diffStatus === 'DELETED';
    return (
        <div className={`flex items-center gap-3 px-4 py-3 rounded-lg border transition-all ${isDeleted
            ? 'border-rose-500/20 bg-rose-500/5 opacity-60'
            : checked
                ? 'border-primary/20 bg-primary/5'
                : 'border-white/5 bg-card/10 hover:bg-card/30'
            }`}>
            <Checkbox
                id={`locale-${locale.code}`}
                checked={checked}
                onCheckedChange={(v) => onToggle(locale.code, !!v)}
                disabled={isDeleted}
                className="h-5 w-5"
            />
            <div className="flex-1 min-w-0">
                <p className={`text-base font-semibold truncate ${isDeleted ? 'line-through text-muted-foreground' : ''}`}>
                    {locale.name}
                </p>
                <div className="flex items-center gap-2 text-base font-mono text-muted-foreground mt-0.5">
                    {locale.code}
                    {remappedTo && remappedTo !== locale.code && (
                        <>
                            <ArrowRight className="h-3.5 w-3.5 text-primary shrink-0" />
                            <span className="text-primary font-bold">{remappedTo}</span>
                        </>
                    )}
                </div>
            </div>
            <div className="flex items-center gap-2 shrink-0">
                <DiffBadge status={locale.diffStatus} />
                {locale.default && (
                    <Badge variant="secondary" className="h-5 px-2 text-base">default</Badge>
                )}
            </div>
        </div>
    );
}

import { useState, useCallback, useMemo, useEffect } from 'react';
import { autoSuggestLocaleMapping, LocaleMapping } from '@/utils/locale-filter';
import type { CTDiffItem, LocaleDiffItem, MigrateDiffResult, EntryDiffItem } from '@/types/smart-migrate';

// ΓöÇΓöÇΓöÇ Types ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export interface TransferStats {
    contentTypes: number;
    entries: { success: number; failed: number };
    assets: number;
}

export interface SmartMigrateOptions {
    clearEnvironment: boolean;
    includeAssets: boolean;
    mergeMode: 'upsert' | 'skip-existing';
}

type Status = 'idle' | 'loading-diff' | 'ready' | 'running' | 'done' | 'error';

export type { CTDiffItem, LocaleDiffItem, MigrateDiffResult, EntryDiffItem };

export interface DiffEntriesResult {
    entries: EntryDiffItem[];
    resolvedAssets: Record<string, { url: string; title: string; isImage: boolean }>;
    resolvedEntries: Record<string, { title: string; contentType?: string }>;
}

// ΓöÇΓöÇΓöÇ Hook ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export function useSmartMigrate() {
    // Source selection
    const [sourceSpaceId, setSourceSpaceId] = useState('');
    const [sourceEnvironmentId, setSourceEnvironmentId] = useState('');

    // Target selection
    const [targetSpaceId, setTargetSpaceId] = useState('');
    const [targetEnvironmentId, setTargetEnvironmentId] = useState('');

    // Diff data
    const [diff, setDiff] = useState<MigrateDiffResult | null>(null);
    const [entriesMap, setEntriesMap] = useState<Record<string, DiffEntriesResult>>({});
    const [loadingEntries, setLoadingEntries] = useState<Set<string>>(new Set());
    const [analyzedCTs, setAnalyzedCTs] = useState<Set<string>>(new Set());
    const [status, setStatus] = useState<Status>('idle');
    const [error, setError] = useState<string | null>(null);

    // Selection: which CTs to migrate
    const [selectedCTIds, setSelectedCTIds] = useState<Set<string>>(new Set());
    const [autoDeps, setAutoDeps] = useState<Set<string>>(new Set());

    // Selection: which individual entries to migrate
    const [selectedEntryIds, setSelectedEntryIds] = useState<Set<string>>(new Set());

    // Selection: which locales to migrate
    const [selectedLocales, setSelectedLocales] = useState<Set<string>>(new Set());
    const [localeMapping, setLocaleMapping] = useState<LocaleMapping>({});

    // Options
    const [options, setOptions] = useState<SmartMigrateOptions>({
        clearEnvironment: false,
        includeAssets: true,
        mergeMode: 'upsert',
    });

    // Result
    const [resultStats, setResultStats] = useState<TransferStats | null>(null);
    const [logs, setLogs] = useState<string[]>([]);

    // ΓöÇΓöÇ Load live diff ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const loadDiff = useCallback(async (
        srcSpace: string,
        srcEnv: string,
        tgtSpace: string,
        tgtEnv: string
    ) => {
        setStatus('loading-diff');
        setError(null);
        setDiff(null);
        setSelectedCTIds(new Set());
        setAutoDeps(new Set());
        setSelectedEntryIds(new Set());
        setSelectedLocales(new Set());
        setEntriesMap({});
        setAnalyzedCTs(new Set());

        try {
            const params = new URLSearchParams({
                sourceSpaceId: srcSpace,
                sourceEnvId: srcEnv,
                targetSpaceId: tgtSpace,
                targetEnvId: tgtEnv,
            });
            const res = await fetch(`/api/smart-migrate/cma-diff?${params}`);
            const json = await res.json();
            if (!json.success) throw new Error(json.error);

            const data = json.data as MigrateDiffResult;
            setDiff(data);
            setStatus('ready');

            // Auto-suggest locale mapping if codes differ
            if (data.sourceLocales && data.targetLocales) {
                const suggested = autoSuggestLocaleMapping(data.sourceLocales, data.targetLocales);
                if (Object.keys(suggested).length > 0) {
                    setLocaleMapping(suggested);
                }
            }
        } catch (e) {
            setError(e instanceof Error ? e.message : 'Failed to load diff');
            setStatus('error');
        }
    }, [sourceSpaceId, sourceEnvironmentId, targetSpaceId, targetEnvironmentId]);

    // ΓöÇΓöÇ Load entries for CT ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const loadEntries = useCallback(async (ctId: string, skip = 0, limit = 100) => {
        if (!sourceSpaceId || !sourceEnvironmentId || !targetSpaceId || !targetEnvironmentId) return;

        setLoadingEntries(prev => new Set(prev).add(ctId));

        try {
            const params = new URLSearchParams({
                sourceSpaceId,
                sourceEnvId: sourceEnvironmentId,
                targetSpaceId,
                targetEnvId: targetEnvironmentId,
                contentTypeId: ctId,
                skip: skip.toString(),
                limit: limit.toString()
            });
            const res = await fetch(`/api/smart-migrate/diff-entries?${params}`);
            const json = await res.json();
            if (!json.success) throw new Error(json.error);

            setEntriesMap(prev => {
                const existing = prev[ctId];
                if (!existing) return { ...prev, [ctId]: json.data };

                // Merge if paginating (for future use)
                return {
                    ...prev,
                    [ctId]: {
                        entries: [...existing.entries, ...json.data.entries],
                        resolvedAssets: { ...existing.resolvedAssets, ...json.data.resolvedAssets },
                        resolvedEntries: { ...existing.resolvedEntries, ...json.data.resolvedEntries }
                    }
                };
            });
        } catch (e) {
            console.error('Failed to load entries for CT', ctId, e);
        } finally {
            setLoadingEntries(prev => {
                const next = new Set(prev);
                next.delete(ctId);
                return next;
            });
        }
    }, [sourceSpaceId, sourceEnvironmentId, targetSpaceId, targetEnvironmentId]);

    // ΓöÇΓöÇ Background Progressive Loader ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    useEffect(() => {
        if (!diff || status !== 'ready') return;

        const ctsToAnalyze = diff.contentTypes.filter(ct =>
            (ct.totalSourceEntries > 0 || ct.totalTargetEntries > 0) &&
            !entriesMap[ct.id] &&
            !loadingEntries.has(ct.id) &&
            !analyzedCTs.has(ct.id)
        );

        if (ctsToAnalyze.length === 0) return;

        // Take up to 3 at a time
        const batch = ctsToAnalyze.slice(0, 3);

        batch.forEach(ct => {
            setAnalyzedCTs(prev => new Set(prev).add(ct.id));
            loadEntries(ct.id).catch(console.error);
        });
    }, [diff, status, entriesMap, loadingEntries, analyzedCTs, loadEntries]);

    // ΓöÇΓöÇ CT selection (with auto-deps from diff dependency map) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const toggleCT = useCallback((ctId: string, checked: boolean) => {
        setSelectedCTIds(prev => {
            const next = new Set(prev);
            if (checked) {
                next.add(ctId);
                const deps = diff?.ctDependencyMap?.[ctId] ?? [];
                const newAutoDeps = new Set<string>();
                for (const dep of deps) {
                    next.add(dep);
                    newAutoDeps.add(dep);
                }
                setAutoDeps(ad => new Set([...ad, ...newAutoDeps]));

                // Auto-select all NEW + MODIFIED entries for this CT (if loaded)
                const loadedData = entriesMap[ctId];
                if (loadedData) {
                    setSelectedEntryIds(prevEntries => {
                        const nextEntries = new Set(prevEntries);
                        for (const entry of loadedData.entries) {
                            if (entry.diffStatus === 'NEW' || entry.diffStatus === 'MODIFIED') {
                                nextEntries.add(entry.id);
                            }
                        }
                        return nextEntries;
                    });
                }
            } else {
                next.delete(ctId);
                setAutoDeps(_ => {
                    const stillNeeded = new Set<string>();
                    for (const selectedId of next) {
                        const deps = diff?.ctDependencyMap?.[selectedId] ?? [];
                        deps.forEach(d => stillNeeded.add(d));
                    }
                    return stillNeeded;
                });

                // Deselect all entries for this CT (if loaded)
                const loadedData = entriesMap[ctId];
                if (loadedData) {
                    setSelectedEntryIds(prevEntries => {
                        const nextEntries = new Set(prevEntries);
                        for (const entry of loadedData.entries) {
                            nextEntries.delete(entry.id);
                        }
                        return nextEntries;
                    });
                }
            }
            return next;
        });
    }, [diff?.ctDependencyMap, diff?.contentTypes]);

    // ΓöÇΓöÇ Entry-level selection ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const toggleEntry = useCallback((entryId: string, checked: boolean) => {
        setSelectedEntryIds(prev => {
            const next = new Set(prev);
            if (checked) next.add(entryId);
            else next.delete(entryId);
            return next;
        });
    }, []);

    const selectAllEntriesForCT = useCallback((ctId: string) => {
        const loadedData = entriesMap[ctId];
        if (!loadedData) return;
        setSelectedEntryIds(prev => {
            const next = new Set(prev);
            for (const entry of loadedData.entries) {
                if (entry.diffStatus !== 'DELETED') {
                    next.add(entry.id);
                }
            }
            return next;
        });
    }, [entriesMap]);

    const clearEntriesForCT = useCallback((ctId: string) => {
        const loadedData = entriesMap[ctId];
        if (!loadedData) return;
        setSelectedEntryIds(prev => {
            const next = new Set(prev);
            for (const entry of loadedData.entries) {
                next.delete(entry.id);
            }
            return next;
        });
    }, [entriesMap]);

    const selectAllCTs = useCallback(() => {
        if (!diff) return;
        const all = new Set(diff.contentTypes.filter(ct => ct.diffStatus !== 'DELETED').map(ct => ct.id));
        setSelectedCTIds(all);

        // Auto-select all changed entries for loaded CTs
        const entryIds = new Set<string>();
        for (const ctId of all) {
            const loadedData = entriesMap[ctId];
            if (loadedData) {
                for (const entry of loadedData.entries) {
                    if (entry.diffStatus !== 'DELETED') {
                        entryIds.add(entry.id);
                    }
                }
            }
        }
        setSelectedEntryIds(entryIds);
    }, [diff, entriesMap]);

    const selectChangedCTs = useCallback(() => {
        if (!diff) return;
        // Without entries loaded, we can only rely on CT status
        // We removed `changedEntryCount` from backend to speed it up.
        // We will select CTs that are NEW or MODIFIED.
        const changed = new Set(
            diff.contentTypes
                .filter(ct => ct.diffStatus === 'NEW' || ct.diffStatus === 'MODIFIED')
                .map(ct => ct.id)
        );
        setSelectedCTIds(changed);
        setAutoDeps(new Set());

        // Auto-select all NEW + MODIFIED entries for changed CTs (if loaded)
        const entryIds = new Set<string>();
        for (const ctId of changed) {
            const loadedData = entriesMap[ctId];
            if (loadedData) {
                for (const entry of loadedData.entries) {
                    if (entry.diffStatus === 'NEW' || entry.diffStatus === 'MODIFIED') {
                        entryIds.add(entry.id);
                    }
                }
            }
        }
        setSelectedEntryIds(entryIds);
    }, [diff, entriesMap]);

    const clearAllCTs = useCallback(() => {
        setSelectedCTIds(new Set());
        setAutoDeps(new Set());
        setSelectedEntryIds(new Set());
    }, []);

    const selectAllChanged = useCallback(() => {
        if (!diff) return;
        // Select all CTs that are NEW/MODIFIED
        const ctIds = new Set<string>();
        const entryIds = new Set<string>();
        for (const ct of diff.contentTypes) {
            if (ct.diffStatus === 'DELETED') continue;
            if (ct.diffStatus === 'NEW' || ct.diffStatus === 'MODIFIED') {
                ctIds.add(ct.id);
                const loadedData = entriesMap[ct.id];
                if (loadedData) {
                    for (const entry of loadedData.entries) {
                        if (entry.diffStatus === 'NEW' || entry.diffStatus === 'MODIFIED') {
                            entryIds.add(entry.id);
                        }
                    }
                }
            }
        }

        // Also add auto deps
        const newAutoDeps = new Set<string>();
        for (const ctId of ctIds) {
            const deps = diff.ctDependencyMap?.[ctId] ?? [];
            for (const d of deps) {
                ctIds.add(d);
                newAutoDeps.add(d);
            }
        }

        setSelectedCTIds(ctIds);
        setAutoDeps(newAutoDeps);
        setSelectedEntryIds(entryIds);

        // Locales
        const changedLocales = diff.locales.filter(l => l.diffStatus === 'NEW' || l.diffStatus === 'MODIFIED').map(l => l.code);
        setSelectedLocales(new Set(changedLocales));
    }, [diff, entriesMap]);

    const toggleLocale = useCallback((code: string, checked: boolean) => {
        setSelectedLocales(prev => {
            const next = new Set(prev);
            if (checked) next.add(code);
            else next.delete(code);
            return next;
        });
    }, []);

    const selectChangedLocales = useCallback(() => {
        if (!diff) return;
        const changed = new Set(
            diff.locales
                .filter(l => l.diffStatus === 'NEW' || l.diffStatus === 'MODIFIED')
                .map(l => l.code)
        );
        setSelectedLocales(changed);
    }, [diff]);

    // ΓöÇΓöÇ Computed values ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const selectedEntryCount = selectedEntryIds.size;
    const changedEntryCount = useMemo(() => {
        if (!diff) return 0;
        let count = 0;
        for (const ct of diff.contentTypes) {
            count += ct.changedEntryCount;
        }
        return count;
    }, [diff]);

    // ΓöÇΓöÇ Execute migration (SSE streaming) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const executeMigration = useCallback(async () => {
        if (!sourceSpaceId || !sourceEnvironmentId || !targetSpaceId || !targetEnvironmentId) return;

        setStatus('running');
        setError(null);
        setLogs([]);

        try {
            const response = await fetch('/api/smart-migrate/live-migrate-stream', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    sourceSpaceId,
                    sourceEnvironmentId,
                    targetSpaceId,
                    targetEnvironmentId,
                    selectedContentTypeIds: Array.from(selectedCTIds),
                    selectedEntryIds: Array.from(selectedEntryIds),
                    selectedLocales: Array.from(selectedLocales),
                    localeMapping,
                    options,
                }),
            });

            if (!response.ok || !response.body) {
                throw new Error(`HTTP ${response.status}`);
            }

            const reader = response.body.getReader();
            const decoder = new TextDecoder();
            let buffer = '';

            while (true) {
                const { done, value } = await reader.read();
                if (done) break;
                buffer += decoder.decode(value, { stream: true });

                const lines = buffer.split('\n');
                buffer = lines.pop() ?? '';

                for (const line of lines) {
                    if (!line.startsWith('data: ')) continue;
                    try {
                        const event = JSON.parse(line.slice(6));
                        if (event.type === 'log') {
                            setLogs((prev: string[]) => [...prev, event.payload as string]);
                        } else if (event.type === 'done') {
                            setResultStats(event.payload.stats as TransferStats);
                            setStatus('done');
                        } else if (event.type === 'error') {
                            setError(event.payload as string);
                            setStatus('error');
                        }
                    } catch { /* malformed SSE line */ }
                }
            }
        } catch (e) {
            setError(e instanceof Error ? e.message : 'Migration failed');
            setStatus('error');
        }
    }, [sourceSpaceId, sourceEnvironmentId, targetSpaceId, targetEnvironmentId,
        selectedCTIds, selectedEntryIds, selectedLocales, localeMapping, options]);

    return {
        // State
        sourceSpaceId, setSourceSpaceId,
        sourceEnvironmentId, setSourceEnvironmentId,
        targetSpaceId, setTargetSpaceId,
        targetEnvironmentId, setTargetEnvironmentId,
        diff,
        entriesMap,
        loadingEntries,
        analyzedCTs,
        status,
        error,
        selectedCTIds,
        autoDeps,
        selectedEntryIds,
        selectedLocales,
        localeMapping, setLocaleMapping,
        options, setOptions,
        resultStats,
        logs,

        // Actions
        loadDiff,
        loadEntries,
        toggleCT,
        toggleEntry,
        selectAllEntriesForCT,
        clearEntriesForCT,
        toggleLocale,
        selectAllCTs,
        selectChangedCTs,
        selectAllChanged,
        clearAllCTs,
        selectChangedLocales,
        executeMigration,

        // Computed
        hasSelection: selectedCTIds.size > 0,
        selectedEntryCount,
        changedEntryCount,
        isLoading: status === 'loading-diff' || status === 'running',
        isDone: status === 'done',
        isReady: status === 'ready',
    };
}

